const Web3 = require("web3");
const web3 = new Web3("https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID");
const account = web3.eth.accounts.privateKeyToAccount('YOUR_PRIVATE_KEY');
web3.eth.accounts.wallet.add(account);

async function sendTransaction(toAddress, value) {
    const transactionParams = {
        gasPrice: '20000000000',
        gas: '21000',
        to: toAddress,
        value: web3.utils.toWei(value, 'ether'),
        from: account.address
    };

    const signedTransaction = await web3.eth.accounts.signTransaction(transactionParams, account.privateKey);
    return web3.eth.sendSignedTransaction(signedTransaction.rawTransaction);
}

async function interactWithSmartContract(contractAddress, abi, methodName, params) {
    const contract = new web3.eth.Contract(abi, contractAddress, {from: account.address});
    const method = contract.methods[methodName];
    return method(...params).send();
}